package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

import static edu.rice.hj.Module0.finish;
import static edu.rice.hj.Module1.async;
import static edu.rice.hj.Module1.doWork;

/**
 * A scorer that works in parallel.
 */
public class IdealParScoring extends AbstractDnaScoring {

    private final int xLength;
    private final int yLength;
    private final int[][] s;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(IdealParScoring::new);
        scoringRunner.start("IdealParScoring", args);
    }

    /**
     * Creates a new IdealParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public IdealParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException(
                "Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }
        this.xLength = xLength;
        this.yLength = yLength;
        s = new int[xLength + 1][yLength + 1];

        s[0][0] = 0;
        for (int ii = 1; ii <= xLength; ii++) {
            s[ii][0] = getScore(1, 0) * ii;
        }
        for (int jj = 1; jj <= yLength; jj++) {
            s[0][jj] = getScore(0, 1) * jj;
        }
    }

    /**
     * This method should be filled in with a parallel implementation of the Smith-Waterman alignment algorithm that
     * maximizes ideal parallelism.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        // Process anti-diagonals: cells on the same anti-diagonal are independent.
        // Anti-diagonal d: cells (i,j) where i+j = d.
        // CPL = xLength + yLength - 1 (number of anti-diagonals).
        // Work = xLength * yLength (one doWork(1) per cell).
        for (int d = 2; d <= xLength + yLength; d++) {
            final int dd = d;
            finish(() -> {
                final int iMin = Math.max(1, dd - yLength);
                final int iMax = Math.min(xLength, dd - 1);
                for (int i = iMin; i <= iMax; i++) {
                    final int ii = i;
                    final int jj = dd - ii;
                    async(() -> {
                        doWork(1);
                        final char xc = x.charAt(ii - 1);
                        final char yc = y.charAt(jj - 1);
                        final int diagScore = s[ii - 1][jj - 1]
                            + getScore(charMap(xc), charMap(yc));
                        final int topScore = s[ii - 1][jj]
                            + getScore(charMap(xc), 0);
                        final int leftScore = s[ii][jj - 1]
                            + getScore(0, charMap(yc));
                        s[ii][jj] = Math.max(diagScore,
                            Math.max(leftScore, topScore));
                    });
                }
            });
        }
        return s[xLength][yLength];
    }

}

package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

import static edu.rice.hj.Module0.finish;
import static edu.rice.hj.Module1.async;

/**
 * A scorer that allocates memory during computation, so that it may compute the scores for two sequences without
 * requiring O(|X||Y|) memory.
 */
public class SparseParScoring extends AbstractDnaScoring {

    private static final int PAR_THRESHOLD = 100;

    private final int xLength;
    private final int yLength;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(SparseParScoring::new);
        scoringRunner.start("SparseParScoring", args);
    }

    /**
     * Creates a new SparseParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public SparseParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException(
                "Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }
        this.xLength = xLength;
        this.yLength = yLength;
    }

    /**
     * Here you should implement a parallel version of the SW alignment algorithm that can support datasets where the
     * size of the S matrix exceeds the available memory.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        final int[] xMap = new int[xLength];
        final int[] yMap = new int[yLength];
        for (int i = 0; i < xLength; i++) {
            xMap[i] = charMap(x.charAt(i));
        }
        for (int j = 0; j < yLength; j++) {
            yMap[j] = charMap(y.charAt(j));
        }

        // O(n) memory: 3 anti-diagonal buffers indexed by row i.
        // diag2[i] = S[i][(d-2)-i] for anti-diagonal d-2
        // diag1[i] = S[i][(d-1)-i] for anti-diagonal d-1
        // diagCurr[i] = S[i][d-i] for current anti-diagonal d
        int[] diag2 = new int[xLength + 1];
        int[] diag1 = new int[xLength + 1];
        int[] diagCurr = new int[xLength + 1];

        // Initialize diag2 for d=0: S[0][0] = 0
        diag2[0] = 0;

        // Initialize diag1 for d=1: S[0][1] and S[1][0]
        diag1[0] = getScore(0, 1);    // S[0][1] = -2
        if (xLength >= 1) {
            diag1[1] = getScore(1, 0); // S[1][0] = -4
        }

        for (int d = 2; d <= xLength + yLength; d++) {
            // Set boundary values in diagCurr
            if (d <= yLength) {
                diagCurr[0] = getScore(0, 1) * d; // S[0][d]
            }
            if (d <= xLength) {
                diagCurr[d] = getScore(1, 0) * d; // S[d][0]
            }

            // Compute interior cells
            final int iMin = Math.max(1, d - yLength);
            final int iMax = Math.min(xLength, d - 1);
            final int numCells = iMax - iMin + 1;

            if (numCells >= PAR_THRESHOLD) {
                final int[] fd2 = diag2;
                final int[] fd1 = diag1;
                final int[] fdc = diagCurr;
                final int fd = d;
                finish(() -> {
                    final int mid = (iMin + iMax) / 2;
                    async(() -> {
                        computeDiagRange(iMin, mid, fd, fd2, fd1, fdc, xMap, yMap);
                    });
                    computeDiagRange(mid + 1, iMax, fd, fd2, fd1, fdc, xMap, yMap);
                });
            } else {
                computeDiagRange(iMin, iMax, d, diag2, diag1, diagCurr, xMap, yMap);
            }

            // Rotate buffers: diag2 <- diag1, diag1 <- diagCurr, diagCurr <- recycled
            int[] temp = diag2;
            diag2 = diag1;
            diag1 = diagCurr;
            diagCurr = temp;
        }

        // After rotation, diag1 holds the last diagonal (d = xLength + yLength)
        return diag1[xLength];
    }

    private void computeDiagRange(final int iStart, final int iEnd, final int d,
            final int[] d2, final int[] d1, final int[] dc,
            final int[] xMap, final int[] yMap) {
        for (int i = iStart; i <= iEnd; i++) {
            final int j = d - i;
            final int xI = xMap[i - 1];
            final int yJ = yMap[j - 1];
            final int diagScore = d2[i - 1] + M[xI][yJ];
            final int topScore = d1[i - 1] + M[xI][0];
            final int leftScore = d1[i] + M[0][yJ];
            dc[i] = Math.max(diagScore, Math.max(leftScore, topScore));
        }
    }

}

package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

import static edu.rice.hj.Module0.finish;
import static edu.rice.hj.Module1.async;

/**
 * A scorer that works in parallel.
 */
public class UsefulParScoring extends AbstractDnaScoring {

    private static final int BLOCK_SIZE = 128;

    private final int xLength;
    private final int yLength;
    private final int[][] s;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(UsefulParScoring::new);
        scoringRunner.start("UsefulParScoring", args);
    }

    /**
     * Creates a new UsefulParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public UsefulParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException(
                "Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }
        this.xLength = xLength;
        this.yLength = yLength;
        s = new int[xLength + 1][yLength + 1];

        s[0][0] = 0;
        for (int ii = 1; ii <= xLength; ii++) {
            s[ii][0] = getScore(1, 0) * ii;
        }
        for (int jj = 1; jj <= yLength; jj++) {
            s[0][jj] = getScore(0, 1) * jj;
        }
    }

    /**
     * Here you should provide an efficient parallel implementation of the Smith-Waterman algorithm that demonstrates
     * real execution time speedup.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        final int[] xMap = new int[xLength];
        final int[] yMap = new int[yLength];
        for (int i = 0; i < xLength; i++) {
            xMap[i] = charMap(x.charAt(i));
        }
        for (int j = 0; j < yLength; j++) {
            yMap[j] = charMap(y.charAt(j));
        }

        final int numBlocksX = (xLength + BLOCK_SIZE - 1) / BLOCK_SIZE;
        final int numBlocksY = (yLength + BLOCK_SIZE - 1) / BLOCK_SIZE;

        // Process block anti-diagonals: blocks on the same anti-diagonal are independent.
        for (int d = 0; d < numBlocksX + numBlocksY - 1; d++) {
            final int dd = d;
            final int bMin = Math.max(0, dd - numBlocksY + 1);
            final int bMax = Math.min(numBlocksX - 1, dd);

            if (bMax > bMin) {
                finish(() -> {
                    for (int b = bMin; b <= bMax; b++) {
                        final int bi = b;
                        final int bj = dd - bi;
                        async(() -> {
                            processBlock(bi, bj, xMap, yMap);
                        });
                    }
                });
            } else {
                processBlock(bMin, dd - bMin, xMap, yMap);
            }
        }

        return s[xLength][yLength];
    }

    private void processBlock(final int bi, final int bj,
            final int[] xMap, final int[] yMap) {
        final int iStart = bi * BLOCK_SIZE + 1;
        final int iEnd = Math.min((bi + 1) * BLOCK_SIZE, xLength);
        final int jStart = bj * BLOCK_SIZE + 1;
        final int jEnd = Math.min((bj + 1) * BLOCK_SIZE, yLength);

        for (int i = iStart; i <= iEnd; i++) {
            final int xI = xMap[i - 1];
            for (int j = jStart; j <= jEnd; j++) {
                s[i][j] = Math.max(
                    s[i - 1][j - 1] + M[xI][yMap[j - 1]],
                    Math.max(
                        s[i - 1][j] + M[xI][0],
                        s[i][j - 1] + M[0][yMap[j - 1]]
                    )
                );
            }
        }
    }

}
